from dataclasses import dataclass

@dataclass
class Item:
    """Represents an item with a name and a price."""
    name: str
    price: float

def calculate_total(items):
    return sum(item['price'] for item in items)

def process_order(order_id, items_data):
    total = calculate_total(items_data)
    return {'order_id': order_id, 'total': total, 'status': 'processed'}

if __name__ == '__main__':
    test_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0}
    ]
    result = process_order('ORD-001', test_items)
    print(f"Order result: {result}")

